// Combine agenda du jour + mails 24h pour Claude.
const mails = $('Mails des dernieres 24h').all();
const events = $('Agenda du jour').all();
if (mails.length === 0 && events.length === 0) {
  return [{ json: { prompt: null, count: 0 } }];
}
const lignesMails = mails.map((it, i) => {
  const m = it.json;
  const from = m.from?.value?.[0]?.address || m.from?.text || m.From || 'inconnu';
  const sujet = m.subject || m.Subject || '(sans objet)';
  const apercu = (m.snippet || m.textPlain || '').toString().slice(0, 300);
  return `${i + 1}. De: ${from}\n   Objet: ${sujet}\n   Apercu: ${apercu}`;
}).join('\n\n');
const lignesAgenda = events.map((it) => {
  const e = it.json;
  const debut = (e.start && (e.start.dateTime || e.start.date)) || '';
  const heure = e.start && e.start.dateTime ? debut.toString().slice(11, 16) : 'journee';
  const titre = e.summary || '(sans titre)';
  const lieu = e.location ? ` (${e.location})` : '';
  return `- ${heure} : ${titre}${lieu}`;
}).join('\n');
const prompt = `Tu es l'assistant matinal d'Alexis. Redige un briefing vocal court en francais, lu a voix haute par une enceinte : pas de markdown, pas de listes a puces, des phrases simples.\n\nCommence par l'agenda du jour : annonce les rendez-vous d'aujourd'hui dans l'ordre, avec l'heure et l'intitule. S'il n'y a aucun rendez-vous, dis-le en une phrase.\n\nEnsuite les mails. Ne retiens QUE ce qui compte vraiment : les messages ecrits par de vraies personnes qui s'adressent a lui (surtout ceux qui attendent une reponse) ; ce qui demande une action ou a une echeance ; les sujets pro, opportunites, contacts reseau, candidatures, clients ; l'argent (factures, paiements, banque, abonnements).\n\nIGNORE totalement : les codes de securite ou 2FA et notifications de connexion ; les newsletters, promotions et alertes emploi automatiques ; les accuses de reception et confirmations automatiques ; les notifications de reseaux sociaux. Si aucun mail n'est notable, dis-le en une phrase, sans meubler.\n\nAgenda du jour:\n${lignesAgenda || 'Aucun rendez-vous.'}\n\nMails (24h):\n${lignesMails || 'Aucun mail.'}`;
return [{ json: { prompt, count: mails.length + events.length } }];
